<script>
import Navbar from "../../components/Navbar.vue";
import Footer from "../../components/Footer.vue";
import DownloadCatalog from "../../components/DownloadCatalog.vue";
import axios from "axios";

export default {
  name: "services-programs",
  components: {
    Navbar: Navbar,
    Footer: Footer,
    DownloadCatalog: DownloadCatalog,
  },
  data() {
    return {
      programs: [],
      sectorRows: [],
      pageTitle: "",
      sidebarLinks: [],
      articles: [],
      imageHeader: "",
      pageBody: "",

      sector_slug: this.$route.params.slug,
      pgLoading: true,
    };
  },
  watch: {
    $route() {
      this.fetchRow();
    },
  },
  created() {
    this.fetchRow();
  },
  methods: {
    fetchRow() {
      axios
        .get(window.baseURL + "/programs")
        .then((res) => {
          var data = res.data.rows;
          console.log(data);
          for (var i = 0; i < data.length; i++) {
            if (data[i].sectors != "") {
              this.sidebarLinks = data[i].sectors;
            }
          }
        })
        .catch((err) => {
          console.log(err);
        });

      // https://api.mazadak.net/api/v1/programs/sectors/Business-Adminsitrators/products
      const url =
        window.baseURL +
        "/programs/sectors/" +
        this.$route.params.slug +
        "/products";
      axios
        .get(url)
        .then((res) => {
          this.pgLoading = false;
          var data = res.data.row;
          this.rows = data;
          this.sectorRows = data;
          this.pageTitle = data.title;
          this.pageBody = data.body;
          this.programs = data.programs;
          this.imageHeader = data.image;
          // console.log(data);
        })
        .catch((err) => {
          console.log(err);
        });
    },
    // Check Auth
    // if (!localStorage.getItem('access_token')) {
    //   this.$router.push({ name: 'Login' });
    // }
  },
};
</script>
