<template>
  <div v-if="cookie" class="cookies-notice">
    <div class="cookies-container container">
      <p>
        {{ $t('app.cookiesBody') }}
        <router-link to="/privacy" class="here-link">{{ $t('app.hereLink') }}</router-link>.
      </p>
      <div class="accept-cookie">
        <button @click="setCookie()" class="read-more" name="button">
          <div>{{ $t('app.acceptBtn') }}</div>
        </button>
      </div>
    </div>
  </div>
</template>

<script>
import axios from "axios";
export default {
  name: "Cookies",
  data() {
    return {
      cookie: true,
    };
  },
  methods: {
    setCookie() {
      this.cookie = false;
      localStorage.setItem('cookie_ll', false);
    },
  },
  created() {
    if(localStorage.getItem('cookie_ll')) {
      this.cookie = false;
    } else {
      this.cookie = true;
    }
  },
};
</script>

