<script>
import axios from "axios";
import SearchPopup from "./SearchPopup";

export default {
  name: "Navbar",
  props: ["close"],
  components: {
    SearchPopup,
  },
  data() {
    return {
      pgLoading: false,
      logo: [],
      header: [],
      pages: [],
      socials: [],
      searchPage: false,
      avatar: "",
      authenticated: false,
      toggleSearch: false,
      toggleMenu: false,
      popularSearch: [],
      langDir: 'en',
      socials: []
    };
  },
  created() {
    if (localStorage.getItem('lang')) {
      this.langDir = localStorage.getItem('lang');
      this.$i18n.local = localStorage.getItem('lang');
      this.$i18n.locale = localStorage.getItem('lang');
      const el = document.body; 
      if (localStorage.getItem('lang') == 'ar') {
        el.classList.add('rtl');
      } else {
        el.classList.remove('rtl');
      }
    }
    axios
      .get(window.baseURL + "/popularSearch")
      .then((res) => {
        const data = res;
        this.popularSearch = res.data.rows;
        console.log(data.data);
      })
      .catch(() => {});

    axios
    .get(window.baseURL + "/setting")
    .then((res) => {
      this.socials = res.data.social;
    })
    .catch(() => { });

    if (this.$route.path == "/search") {
      this.searchPage = true;
    } else {
      this.searchPage = false;
    }

    if (!localStorage.getItem("access_token")) {
      this.authenticated = false;
    } else {
      this.authenticated = true;
    }

    if (!localStorage.getItem("avatar")) {
      this.avatar = false;
    } else {
      this.avatar = localStorage.getItem("avatar");
    }

    this.fetchLogo();
    this.fetchPages();
    this.scrollToTop();
  },
  methods: {
    scrollToTop() {
      window.scrollTo(0,0);
    },
    toggleLang() {
      const el = document.body;
      if (this.langDir == 'en') {
        el.classList.add('rtl');
        this.langDir = 'ar';
        localStorage.setItem('lang', 'ar');
        this.$i18n.local = 'ar';
        this.$i18n.locale = 'ar';
      } else {
        el.classList.remove('rtl');
        this.langDir = 'en';
        localStorage.setItem('lang', 'en');
        this.$i18n.local = 'en';
        this.$i18n.locale = 'en';
      }

    },

    opnPopular(slug) {
      this.$router.push({
        name: "show-popular-search",
        params: { slug: slug },
      });
      // refersh
      location.reload();
    },

    fetchLogo() {
      // Get Navbar Links
      axios
        .get(window.baseURL + "/setting")
        .then((res) => {
          var data = res.data;
          this.logo = res.data.logo;
          this.socials = res.data.social;
          this.header = res.data.header;
          console.log(data);
        })
        .catch(() => {});
    },

    //Get Navbar Links in Big Sizes
    fetchPages() {
      axios
        .get(window.baseURL + "/pages")
        .then((res) => {
          var data = res.data.rows;
          this.pages = res.data.rows;
        })
        .catch(() => {});
    },

    logout() {
      localStorage.clear();
      this.$router.push({ name: "login" });
    },

    openMenu() {
      let el1 = document.querySelector(".navbar-container");
      let el2 = document.querySelector(".navbar-backdrop");
      el1.classList.add("active");
      el2.classList.add("active");
    },

    closeMenu() {
      let el1 = document.querySelector(".navbar-container");
      let el2 = document.querySelector(".navbar-backdrop");
      el1.classList.remove("active");
      el2.classList.remove("active");
    },
  },
  mounted() {
    
  },
};
</script>
