<script>
import Navbar from "../../components/Navbar.vue";
import Footer from "../../components/Footer.vue";
import axios from "axios";
import vSelect from "vue-select";
import "vue-select/dist/vue-select.css";

export default {
  name: "people",
  components: {
    Navbar: Navbar,
    Footer: Footer,
    vSelect: vSelect,
  },
  data() {
    return {
      btnLoading: false,
      pgLoading: true,
      toggleFilter: false,
      layout: [],

      locations: [],
      locationId: "",

      offices: [],
      officeId: '',

      sector: [],
      sectorId: '',

      subSector: [],
      subSectorId: '',

      services: [],
      serviceId: '',

      subService: [],
      subServiceId: '',

      sort: [
        {id: 'asc', name: 'Asc'},
        {id: 'desc', name: 'Desc'},
      ],
      sortId: '',

      row: [],
      items: [],
    };
  },
  watch: {
    $route() {
      this.fetchRow();
      this.fetchLocation();
    },

   'locationId'  : function (val, oldval) {
      this.fetchOffices();
      this.fetchRow();
      this.toggleFilter = false;
    },
    'officeId'  : function (val, oldval) {
      this.fetchRow();
      this.toggleFilter = false;
    },
    'sectorId'  : function (val, oldval) {
      this.fetchSubSector();
      this.fetchRow();
      this.toggleFilter = false;
    },
    'subSectorId'  : function (val, oldval) {
      this.fetchRow();
      this.toggleFilter = false;
    },
    'serviceId'  : function (val, oldval) {
      this.fetchSubService();
      this.fetchRow();
      this.toggleFilter = false;
    },
    'subServiceId'  : function (val, oldval) {
      this.fetchRow();
      this.toggleFilter = false;
    },
    'sortId'  : function (val, oldval) {
      this.fetchRow();
      this.toggleFilter = false;
    },
  },
  created() {
    this.fetchRow();
    this.fetchLocation();
    this.fetchSector();
    this.fetchService();
  },

  methods: {
    fetchRow(){
      this.pgLoading = true;
      axios.defaults.headers.common = {
          'X-Requested-With': 'XMLHttpRequest', // security to prevent CSRF attacks
      };
      const options = {
          url: window.baseURL + '/people',
          method: 'GET',
          data: {},
          params: {
            location_id: this.locationId,
            office_id: this.officeId,
            sector_id: this.sectorId,
            subsector_id: this.subsectorId,
            service_id: this.serviceId,
            subservice_id: this.subserviceId,
            sort: this.sortId, 
          }
      }
      axios(options)
        .then(res => {
            this.pgLoading = false;
            this.items = res.data.rows;
            this.layout = res.data.layout;
        })
        .catch(() => { })
        .finally(() => { });
  },

    fetchLocation() {
      axios
        .get(window.baseURL + "/people-locations")
        .then((res) => {
          this.pgLoading = false;
          this.locations = res.data.rows;
        })
        .catch(() => {})
        .finally(() => {});
    },

    fetchSector() {
      axios
        .get(window.baseURL + '/people-sectors')
        .then((res) => {
          this.sector = res.data.rows;
        })
        .catch((error) => {
          console.log(error);
        })
        .finally(() => {});
    },

    fetchService() {
      axios
        .get(window.baseURL + '/people-services')
        .then((res) => {
          this.services = res.data.rows;
        })
        .catch((error) => {
          console.log(error);
        })
        .finally(() => {});
    },

    // locationsFilter() {
    //   const data = {
    //     id: locationId,
    //   };
    //   axios
    //     .post(window.baseURL + "/people-locations", data)
    //     .then((res) => {
    //       const data = res.data.rows;
    //       console.log(res);
    //     })
    //     .catch((error) => {
    //       console.log(error);
    //     })
    //     .finally(() => {});
    // },

    fetchOffices() {
      axios
        .get(window.baseURL + '/people-offices/' + this.locationId)
        .then((res) => {
          this.offices = res.data.rows;
        })
        .catch((error) => {
          console.log(error);
        })
        .finally(() => {});
    },

    fetchSubSector() {
      axios
        .get(window.baseURL + '/people-subsectors/' + this.sectorId)
        .then((res) => {
          this.subSector = res.data.rows;
        })
        .catch((error) => {
          console.log(error);
        })
        .finally(() => {});
    },

    fetchSubService() {
      axios
        .get(window.baseURL + '/people-subservices/' + this.serviceId)
        .then((res) => {
          this.subService = res.data.rows;
        })
        .catch((error) => {
          console.log(error);
        })
        .finally(() => {});
    },
  },
};
</script>
