            <div class="a-arrows">
              <button @click="prev" class="arrow-btn">
                <span class="icon-arrow-left icon-arr"></span>
              </button>
              <button @click="next" class="arrow-btn">
                <span class="icon-arrow-right icon-arr"></span>
              </button>
            </div>
          </div>
          <swiper ref="mySwiper" :options="swiperOptions">
            <swiper-slide v-for="(row, index) in rows" :key="index" :data-swiper-autoplay="row.duration + '000'">
              <div class="a-program-card">
                <img :src="row.image" class="a-program-card-view img-fluid" alt="" />
                <div class="a-program-cbody">

                  <div class="title" v-html="$i18n.locale == 'ar' ? row.title_ar : row.title"></div>
                  
                  <router-link v-if="row.button" :to="row.redirect" class="d-inline-block a-rd-more-btn">
                    <div class="d-flex align-items-center">
                      <span v-html="$i18n.locale == 'ar' ? row.button_ar : row.button"></span>
                      <span class="icon-back icon"></span>
                    </div>
                  </router-link>
                </div>
              </div>
