<script>
// Very Important npm install swiper@5.4.5 
import axios from 'axios';
import { Swiper, SwiperSlide, directive } from 'vue-awesome-swiper';
import 'swiper/css/swiper.css';

export default {
  name: "Section1",
  components: {
    Swiper,
    SwiperSlide
  },
  directives: {
    swiper: directive
  },
  data() {
    return {
      rows: [],
      duration: 5,
      speed: 800,
      swiperOptions: {
        loop: false,
        autoplay: {
          // delay: 4000, or data-swiper-autoplay="2000" in html
        },
        spaceBetween: 30,
        // slidesPerView: 3,
        navigation: {
            nextEl: '.swiperNext',
            prevEl: '.swiperPrev'
        },
        breakpoints: {
          767: {
            slidesPerView: 1,
            spaceBetween: 0,
          },
          768: {
            slidesPerView: 2
          },
          1200: {
            slidesPerView: 2
          }
        }
      }
    }
  },
  created() {
    this.fetchSlider();
  },
  computed: {
    swiper() {
      return this.$refs.mySwiper.$swiper
    }
  },
  methods: {
    prev() {
			this.$refs.mySwiper.$swiper.slidePrev();
		},
		next() {
			this.$refs.mySwiper.$swiper.slideNext();
		},
    fetchSlider() {
      axios
        .get(window.baseURL + "/programsInHome")
        .then((res) => {
          this.pgLoading = false;
          this.rows = res.data.row;
        })
        .catch(() => {});
    },
  },
  mounted() {
    this.swiper.slideTo(3, 1000, false)
  }
}
</script>
