<script>
import Navbar from "../../components/Navbar.vue";
import Footer from "../../components/Footer.vue";
import Avatar from "../../components/Avatar.vue";
import axios from "axios";

export default {
  name: "Profile",
  components: {
    Navbar: Navbar,
    Footer: Footer,
    Avatar: Avatar,
  },
  data() {
    return {
      data: [],
      accessToken: "",
      first_name: "",
      last_name: "",
      mobile: "",
      company: "",
      country: "",
      website: "",
      avatar: "",
      base64Image: "",
      preview: "",
      btnLoading: false,
      countries: [],
      certificates: [
        {
          title: "Professional Certificate in Human Resources",
          code: "Dip/USA/108TMR99830",
          image: require("../../assets/img/Certificate-of-Diploma.png"),
        },
        {
          title: "Professional Certificate in Human Resources",
          code: "Dip/USA/108TMR99830",
          image: require("../../assets/img/Certificate-of-Achievement.png"),
        },
        {
          title: "Professional Certificate in Human Resources",
          code: "Dip/USA/108TMR99830",
          image: require("../../assets/img/Certificate-of-Diploma.png"),
        },
      ],
      switchProfileSetting: false,
    };
  },
  created() {
    //Check Auth
    if (!localStorage.getItem("access_token")) {
      this.$router.push({ name: "login" });
    }
    
    this.firstName = localStorage.getItem('user_name');
    this.lastName = localStorage.getItem('last_name');
    this.country = localStorage.getItem('country');
    this.accessToken = localStorage.getItem("access_token");

    //fetch user Data
    this.fetchUserData();
    //fetch countries
    this.fetchCountries();

  },
  mounted() {
    $(function () {
      var hash = window.location.hash;
      hash && $('.profile-links a[href="' + hash + '"]').tab("show");
      if (hash) {
        var titleHash = $('a[href="' + hash + '"]')
          .find(".profile-link-text")
          .text();
        $("#tabTitle").text(titleHash);
      }

      $(".nav-tabs a").click(function (e) {
        var title = $(this).find(".profile-link-text").text();
        $(this).tab("show");
        $("#tabTitle").text(title);
        var scrollmem = $("body").scrollTop();
        window.location.hash = this.hash;
        $("html,body").scrollTop(scrollmem);
      });
    });
  },
  methods: {
    switchProfileBtn: function () {
      this.switchProfileSetting = !this.switchProfileSetting;
    },
    fetchUserData() {
      const options = {
        url: window.baseURL + "/myProfile",
        method: "GET",
        headers: {
          Authorization: "Bearer " + this.accessToken,
        },
      };
      axios(options)
        .then((res) => {
          const data = res.data.row;
          this.first_name = data.first_name;
          this.last_name = data.last_name;
          this.mobile = data.mobile;
          this.company = data.company;
          this.country = data.country;
          this.website = data.website;
          this.preview = data.avatar;
          this.data = data;
        })
        .catch((err) => {
            localStorage.clear();
            this.$router.push({ name: 'login' });
        });
    },
    updateUserData() {
      const options = {
        url: window.baseURL + "/myProfile",
        method: "POST",
        data: {
          first_name: this.first_name,
          last_name: this.last_name,
          mobile: this.mobile,
          company: this.company,
          country: this.country,
          website: this.website,
        },
        headers: {
          Authorization: "Bearer " + this.accessToken,
        },
      };
      axios(options)
        .then((res) => {
          const data = res.data.row;
          this.fetchUserData();
        })
        .catch(() => {
        });
    },

    onImageChange(e) {
      this.btnLoading = true;
      const file = e.target.files[0];
      this.preview = URL.createObjectURL(file);
      this.createBase64Image(file);
    },
    createBase64Image(fileObject) {
      const reader = new FileReader();
      reader.readAsDataURL(fileObject);
      reader.onload = (e) => {
        this.base64Image = e.target.result;
        this.apply();
      };
    },

    apply() {
      this.btnLoading = true;
      // this.apply();
      axios.defaults.headers.common = {
        "X-Requested-With": "XMLHttpRequest", // security to prevent CSRF attacks
      };

      const options = {
        url: window.baseURL + "/myProfile",
        method: "POST",
        data: {
          avatar: this.base64Image,
        },
        headers: {
          Authorization: "Bearer " + this.accessToken,
        },
      };

      axios(options)
        .then((res) => {
          this.btnLoading = false;
          this.errors = false;
          localStorage.setItem("avatar", this.base64Image);
          this.success = "Application Completed Successfully.";
          this.fetchUserData();
        })
        .catch((err) => {
          this.btnLoading = false;
          this.success = false;
          this.errors = err.response ? err.response.data.message : "" + err;
        })
        .finally(() => {});
    },

    fetchCountries() {
      this.countryLoading = true;
      axios.defaults.headers.common = {
        "X-Requested-With": "XMLHttpRequest", // security to prevent CSRF attacks
      };
      const options = {
        url: window.baseURL + "/countries",
        method: "GET",
        data: {},
        params: {},
      };
      axios(options)
        .then((res) => {
          this.countryLoading = false;
          this.countries = res.data.rows.countries;
        })
        .catch(() => {})
        .finally(() => {});
    },

    logout(){
      localStorage.clear();
      this.$router.push({ name: 'login' });
    },
    
  },
};
</script>
