  <div class="am-slider-container">
    <swiper class="swiper-container" ref="mySwiper" :options="swiperOptions">

        <swiper-slide class="swiper-slider" v-for="(row, index) in rows" :key="index" :data-swiper-autoplay="row.duration + '000'">
            <div class="slide-card" :style="{backgroundImage: `url(${row.file}) !important`}">
                <div class="container-fluid">

                  <div class="slide-widget" :style="{backgroundColor: `${row.bgColor} !important`}">
                    <div class="sb-tit">
                        <div class="sub-title d-inline-block" :style="{borderBottom: `4px solid ${row.lineColor}`}" v-html="$i18n.locale == 'ar' ? row.subTitle_ar : row.subTitle"></div>
                    </div>
                    <div class="us-bg-title" v-html="$i18n.locale == 'ar' ? row.title_ar :  row.title"></div>
                    <div class="text" v-html="$i18n.locale == 'ar' ? row.body_ar : row.body"></div>
                    <div>
                      <router-link v-if="row.button" :to="row.redirect" class="us-btn" v-html="$i18n.locale == 'ar' ? row.button_ar : row.button"></router-link>
                    </div>
                    <div class="box-bg-color" :style="{backgroundColor: `${row.boxColor} !important`}"></div>
                    <div class="box-bg-color box-bg-color-1" :style="{backgroundColor: `${row.box2Color ? row.box2Color : '#001157'} !important`}"></div>
                    <div class="box-bg-color box-bg-color-2" :style="{backgroundColor: `${row.box3Color ? row.box3Color : '#001157'} !important`}"></div>
